// PrayerLibrary.swift
// Rotating morning and evening prayers — one per day, cycling every 200 days

import Foundation

struct PrayerLibrary {

    // MARK: - Morning Anchor Prayer (rotates daily)
    static func morningPrayerForToday() -> String {
        let dayOfYear = max(1, Calendar.current.ordinality(of: .day, in: .year, for: Date()) ?? 1)
        return morningPrayers[(dayOfYear - 1) % morningPrayers.count]
    }

    // MARK: - Evening Arrow Prayer (rotates daily)
    static func eveningPrayerForToday() -> String {
        let dayOfYear = max(1, Calendar.current.ordinality(of: .day, in: .year, for: Date()) ?? 1)
        return eveningPrayers[(dayOfYear - 1) % eveningPrayers.count]
    }

    // MARK: - 200 Morning Prayers
    static let morningPrayers: [String] = [
        "Lord, open my eyes to what is pulling me off course today. I anchor myself in You. Not in my own strength. You are my rock. Anchor me in Your truth. I stand firm today not in my own strength but in Yours. Fill me with Your Spirit. Guard my heart and mind. In Jesus' name, Amen.",
        "Father, I suit up in Your armor today. Truth, righteousness, faith, salvation, the Word, and prayer. I am fully dressed for battle. I reject every distraction that pulls me from You. Today I am anchored. Today I am watchful. Today I am Yours. In Jesus' name, Amen.",
        "Jesus, I surrender this day to You. Not my will but Yours. I release my grip on the outcome. Let everything I do today be done for Your glory and in Your love. I am not my own. I was bought at a price. In Jesus' name, Amen.",
        "God, alert me. Sharpen my spiritual sight today. I refuse to be caught sleeping. Open my eyes to what the enemy is doing. Open my eyes to see You at work today. In the ordinary moments, in the difficult conversations, in the quiet spaces. You are there. In Jesus' name, Amen.",
        "Lord, I choose Your strength over my own today. When I am weak, You are strong. I stop pretending and start depending. I put on the full armor of God today. Belt of truth, breastplate of righteousness, shoes of peace, shield of faith, helmet of salvation, sword of the Spirit. I am dressed for war. In Jesus' name, Amen.",
        "Father, show me the way of escape today. No temptation is beyond Your faithfulness. Show me the door and I will walk through it. Make me the man my family needs today. Present, patient, purposeful, and anchored in Christ. In Jesus' name, Amen.",
        "Lord, You are my strength. I will not fear what man can do to me. You go before me into every battle. I choose faith over fear today. Not because the path is clear, but because the God who leads is faithful. In Jesus' name, Amen.",
        "Renew my mind, God. Let me think Your thoughts today. Tear down every pattern that contradicts Your truth. Anchor me in Your truth. I stand firm today not in my own strength but in Yours. Fill me with Your Spirit. Guard my heart and mind. In Jesus' name, Amen.",
        "Jesus, I lay this down at Your feet. I take Your yoke instead. It is easy and light because You carry it with me. I reject every distraction that pulls me from You. Today I am anchored. Today I am watchful. Today I am Yours. In Jesus' name, Amen.",
        "Lord, make me a man after Your own heart. Not perfect but pursuing. Not flawless but faithful. Shape me today. Let everything I do today be done for Your glory and in Your love. I am not my own. I was bought at a price. In Jesus' name, Amen.",
        "Father, guard my heart today. From the heart flow the springs of life. Let nothing corrupt the source. Open my eyes to see You at work today. In the ordinary moments, in the difficult conversations, in the quiet spaces. You are there. In Jesus' name, Amen.",
        "God, humble me before I humble myself. Pride goes before destruction. Kill my pride before it kills what matters. I put on the full armor of God today. Belt of truth, breastplate of righteousness, shoes of peace, shield of faith, helmet of salvation, sword of the Spirit. I am dressed for war. In Jesus' name, Amen.",
        "Lord, anchor me in Your Word today. Not my feelings, not the culture, not popular opinion. Your Word alone is my foundation. Make me the man my family needs today. Present, patient, purposeful, and anchored in Christ. In Jesus' name, Amen.",
